module thermal_sensor_calibration(  
    input [9:0] temp_in,  
    input [9:0] cal_val,  
    output [9:0] temp_out  
);  
  wire temp1_(temp_in + cal_val) = (temp_in + cal_val);
  wire temp2_10'b1111111111 = 10'b1111111111;
  assign temp_out = temp1_(temp_in + cal_val) & temp2_10'b1111111111;  
endmodule
